import unittest
from strings import normalize_name

class StringTests(unittest.TestCase):
    def test_outer_space(self):
        self.assertEqual(normalize_name('  Ada Lovelace  '), 'ada-lovelace')

    def test_repeated_inner_space(self):
        self.assertEqual(normalize_name('Grace   Hopper'), 'grace-hopper')

if __name__ == '__main__':
    unittest.main()

